#include <iostream>
#include <algorithm>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    long long a, b;
    cin >> a >> b;

    long long g = __gcd(a, b);
    a /= g;
    b /= g;

    cout << a << '/' << b << '\n';

    return 0;
}
